<?php
namespace App\Controllers;
use App\Core\Controller; use App\Models\BaseCatalog;
class MovimientoController extends Controller { public function entregas():void{$this->requirePermission('Entrega de materiales');$m=new BaseCatalog;$rows=$m->fetchAll('SELECT e.*, CONCAT(r.nombre," ",r.apellido) receptor, CONCAT(a.nombre," ",a.apellido) entrega FROM entregas_materiales e JOIN usuarios r ON r.id=e.usuario_receptor_id JOIN usuarios a ON a.id=e.usuario_entrega_id ORDER BY e.id DESC');$this->view('entregas/index',compact('rows'));} public function recepciones():void{$this->requirePermission('Recepción de materiales');$m=new BaseCatalog;$rows=$m->fetchAll('SELECT r.*, CONCAT(d.nombre," ",d.apellido) devuelve, CONCAT(a.nombre," ",a.apellido) recibe FROM recepciones_materiales r JOIN usuarios d ON d.id=r.usuario_devuelve_id JOIN usuarios a ON a.id=r.usuario_recibe_id ORDER BY r.id DESC');$this->view('recepciones/index',compact('rows'));} public function formEntrega():void{$this->requirePermission('Entrega de materiales','crear');$m=new BaseCatalog;$usuarios=$m->all('usuarios','nombre');$materiales=$m->all('materiales','nombre_material');$this->view('entregas/form',compact('usuarios','materiales'));} public function saveEntrega():void{verify_csrf();$this->requirePermission('Entrega de materiales','crear');$db=\App\Core\App::db();$db->beginTransaction();try{$m=new BaseCatalog;$m->execSql('INSERT INTO entregas_materiales(usuario_receptor_id,usuario_entrega_id,fecha_entrega,observacion,estado,created_at) VALUES(?,?,?,?,?,NOW())',[$_POST['usuario_receptor_id'],current_user()['id'],$_POST['fecha_entrega'],$_POST['observacion'],'activa']);$eid=(int)$db->lastInsertId();foreach($_POST['material_id']??[] as $i=>$mid){$cant=(float)$_POST['cantidad'][$i]; if($cant<=0)continue; $mat=$m->fetch('SELECT stock_actual FROM materiales WHERE id=? FOR UPDATE',[$mid]); if($cant>$mat['stock_actual']) throw new \RuntimeException('Stock insuficiente'); $after=$mat['stock_actual']-$cant; $m->execSql('UPDATE materiales SET stock_actual=? WHERE id=?',[$after,$mid]); $m->execSql('INSERT INTO entrega_material_detalle(entrega_id,material_id,cantidad_entregada,stock_antes,stock_despues,cantidad_disponible) VALUES(?,?,?,?,?,?)',[$eid,$mid,$cant,$mat['stock_actual'],$after,$cant]); $m->execSql('INSERT INTO kardex_materiales(material_id,tipo_movimiento,cantidad,stock_antes,stock_despues,referencia_tipo,referencia_id,usuario_id,fecha) VALUES(?,?,?,?,?,?,?,?,NOW())',[$mid,'salida_entrega',$cant,$mat['stock_actual'],$after,'entrega',$eid,current_user()['id']]);}$m->audit('Crear','Entrega de materiales',$eid,'Entrega registrada');$db->commit();flash('success','Entrega registrada.');redirect('entregas-materiales');}catch(\Throwable $e){$db->rollBack();flash('error',$e->getMessage());redirect('entregas-materiales/crear');}} }
